   - UserRole = 'user' | 'admin'
   - EventStatus = 'upcoming' | 'ongoing' | 'ended'
   - ParticipantRole = 'host' | 'participant'
   - User { id: string, email: string, name: string, avatar_url: string | null, role: UserRole, created_at: string, updated_at: string }
   - Event { id, title, description, location, event_date, cover_image_url, invite_code, status: EventStatus, created_by, created_at, updated_at }
   - EventParticipant { id, event_id, user_id, role: ParticipantRole, joined_at }
   - EventWithHost = Event & { host: Pick<User, 'id'|'name'|'avatar_url'> }
   - EventWithCount = Event & { participant_count: number }
   - EventWithParticipants = EventWithHost & { participants: (EventParticipant & { user: User })[] }
   - ApiResponse<T> = { data: T | null, error: string | null }
   - PaginatedResponse<T> = { data: T[], count: number, page: number, per_page: number }
